# Utility module with helper functions and classes

from geometry import Point

def calculate_distance(p1: Point, p2: Point) -> float:
    return p1.distance_to(p2)

def format_shape_info(shape_type: str, area: float) -> str:
    return shape_type + "=" + str(area)

class ShapeStats:
    total_area: float

    def __init__(self):
        self.total_area = 0.0

    def add_shape(self, area: float):
        self.total_area += area
